#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
ll n,sum[15],ans,cnt;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=10;i++)
	{
		sum[i]=sum[i-1]+i;
	}
	for(ll num=1;n>0;n/=10,num*=10)
	{
		int t=n%10;
		ans+=num*(45*(n/10)+sum[max(t-1,0)])+t*(cnt+1);
		cnt+=t*num;
	}
	cout<<ans;
	return 0;
}
